// Agent 11: format output â€” plain markdown cover letter (not JSON).
// Mode: Run Once for All Items
// Propagates structured error from Call LLM on failure.
// Falls back to the original cover letter markdown when refinement fails or is
// unusable, so downstream still has a valid letter to work with.

const callLLM = $('Call LLM').first().json;
const originalMarkdown = $('Set Inputs').first().json.cover_letter_markdown || '';

// Call LLM failed â€” propagate error, fall back to original
if (callLLM.success === false) {
  console.log(`[Agent 11] LLM call failed: ${callLLM.error?.category || 'unknown'} â€” ${callLLM.error?.message || 'no message'}`);
  console.log(`[Agent 11] Falling back to original cover letter markdown (${originalMarkdown.length} chars)`);
  return {
    json: {
      success: false,
      cover_letter_markdown: originalMarkdown,
      refined: false,
      tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
      cached_input_tokens: callLLM.cached_input_tokens || 0,
      cache_write_tokens: callLLM.cache_write_tokens || 0,
      model_used: callLLM.model_used || 'unknown',
      provider_used: callLLM.provider_used || 'unknown',
      errors: [...(callLLM.errors || [])],
      error: callLLM.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: callLLM.provider_used || 'unknown',
        model: callLLM.model_used || 'unknown'
      }
    }
  };
}

// Normal path: parse refined markdown from content
const response = $input.item.json;
const text = response.text || response.content || response.response || response.output_text || response.completion || '';

const parseErrors = [];
let refinedMarkdown = '';

if (!text) {
  parseErrors.push(`No text returned from Call LLM. Keys: ${Object.keys(response).join(', ')}`);
  console.log(`[Agent 11] ${parseErrors[parseErrors.length - 1]}`);
} else {
  refinedMarkdown = String(text).trim();
  // Strip markdown code fences if the LLM wrapped the output (defensive)
  refinedMarkdown = refinedMarkdown
    .replace(/^```(?:markdown|md)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}

// Quality checks: too short OR identical to input
const tooShort = refinedMarkdown.length <= 80;
const identicalToOriginal = refinedMarkdown.length > 0 && refinedMarkdown === originalMarkdown;
const refined = !tooShort && !identicalToOriginal;

let error = null;
if (parseErrors.length > 0) {
  error = {
    category: 'output_quality',
    type: 'empty_output',
    message: parseErrors.join('; '),
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
} else if (tooShort) {
  parseErrors.push(`Refined output too short (${refinedMarkdown.length} chars)`);
  error = {
    category: 'output_quality',
    type: 'short_output',
    message: parseErrors[parseErrors.length - 1],
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
} else if (identicalToOriginal) {
  parseErrors.push('Refined output identical to original');
  error = {
    category: 'output_quality',
    type: 'no_change',
    message: parseErrors[parseErrors.length - 1],
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
}

const success = refined;

console.log(`[Agent 11] Refined: ${refined}, length: ${refinedMarkdown.length} chars`);
console.log(`[Agent 11] Tokens: ${callLLM.input_tokens || 0}in + ${callLLM.output_tokens || 0}out + ${callLLM.cached_input_tokens || 0}cached + ${callLLM.cache_write_tokens || 0}cache_write`);

return {
  json: {
    success,
    cover_letter_markdown: refined ? refinedMarkdown : originalMarkdown,
    refined,
    tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
    cached_input_tokens: callLLM.cached_input_tokens || 0,
    cache_write_tokens: callLLM.cache_write_tokens || 0,
    model_used: callLLM.model_used || 'unknown',
    provider_used: callLLM.provider_used || 'unknown',
    errors: parseErrors,
    error
  }
};

// Set Inputs â€” Agent 11: Cover Letter Fine Refiner (user-instruction driven)
// Mirrors Agent 9 (Resume Fine Refiner) for cover letters.
// Model/provider/max_tokens are config-only (config.*_cover_letter_refiner) â€” single source of truth.
// Trigger field for the instruction is `user_command` (the caller's contract).
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') cleaned = cleaned.substring(1);
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);
const descriptionHtml = strip(trigger.description_html);
const coverLetterMarkdown = strip(trigger.cover_letter_markdown);
const masterDoc = strip(trigger.master_doc);
const userCommand = strip(trigger.user_command || trigger.refinement_instructions);

// Optional prior verifier (from the previous version). May arrive as Object or JSON-string.
let verifier = trigger.verifier;
if (typeof verifier === 'string') {
  let raw = verifier;
  while (raw.length > 0 && raw.charAt(0) === '=') raw = raw.substring(1);
  try { verifier = JSON.parse(raw); }
  catch (e) { console.log('[Agent 11 Set Inputs] verifier not parseable JSON, defaulting to empty'); verifier = {}; }
}
verifier = verifier || {};
if (verifier.result && typeof verifier.result === 'object') verifier = verifier.result;

// Provider / model / max_tokens are config-only (config.*_cover_letter_refiner). Throw loud if missing.
const provider = strip(config.provider_cover_letter_refiner);
if (!provider) {
  throw new Error('[Agent 11] config.provider_cover_letter_refiner is required. Set it in your config sheet (anthropic | openai | gemini).');
}
const model = strip(config.model_cover_letter_refiner);
if (!model) {
  throw new Error('[Agent 11] config.model_cover_letter_refiner is required. Set it in your config sheet.');
}
const maxTokens = Number(config.max_tokens_cover_letter_refiner);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 11] config.max_tokens_cover_letter_refiner is required and must be a number.');
}

if (!userCommand) {
  throw new Error('[Agent 11] user_command (refinement instructions) is required for cover-letter refine mode.');
}

console.log(`[Agent 11 Set Inputs] cover_letter: ${coverLetterMarkdown.length} chars, master_doc: ${masterDoc.length} chars, instructions: ${userCommand.length} chars, prior verifier issues: ${(verifier.issues || []).length}, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    description_html: descriptionHtml,
    cover_letter_markdown: coverLetterMarkdown,
    master_doc: masterDoc,
    refinement_instructions: userCommand,
    verifier,
    provider,
    model,
    max_tokens: maxTokens
  }
};

// Build Prompt â€” Agent 11: Cover Letter Fine Refiner (user-instruction driven)
// Mirrors Agent 9's structure for cover letters: user instructions are the primary
// driver; prior verifier findings are an optional secondary input folded in when present.
const input = $input.item.json;
const systemPrompt = input.system_prompt || '';
const masterDoc = input.master_doc || '';
const coverLetterMarkdown = input.cover_letter_markdown || '';
const verifier = input.verifier || {};
const descriptionHtml = input.description_html || '';
const instructions = input.refinement_instructions || '';

if (!systemPrompt || systemPrompt.length < 200) {
  throw new Error(`[Agent 11] system_prompt missing or too short (${systemPrompt.length} chars). Check Prompt Loader / prompts tab (agent_11) and caller mapping.`);
}
if (!coverLetterMarkdown || coverLetterMarkdown.length < 80) {
  throw new Error(`[Agent 11] cover_letter_markdown missing or too short (${coverLetterMarkdown.length} chars). Check parent cover letter in the request.`);
}
if (!masterDoc || masterDoc.length < 200) {
  throw new Error(`[Agent 11] master_doc missing or too short (${masterDoc.length} chars). Check Data Loader output.`);
}
if (!instructions) {
  throw new Error('[Agent 11] refinement_instructions missing â€” required for refine mode.');
}

const OUTPUT_CONTRACT = `## OUTPUT CONTRACT
- Output ONLY the refined cover letter markdown.
- Do NOT wrap in JSON or any envelope.
- Do NOT prepend or append commentary, preamble, or summary.
- Start directly with the cover letter's first line.
- Preserve the letter's existing structure (opening, body paragraphs, closing) unless the instructions explicitly ask to restructure.
- Output must be 100% faithful to the master doc â€” no invented facts, no embellishments.
- Keep the letter relevant and addressed to the target job throughout.
- Apply the candidate's revision instructions as the primary driver.
- Keep it the natural length of a cover letter â€” do not pad.`;

// Prior verifier is optional â€” include the block only if it carries findings.
const hasVerifier = verifier && Array.isArray(verifier.issues) && verifier.issues.length > 0;
const verifierBlock = hasVerifier
  ? `\n\n# PRIOR VERIFIER FINDINGS (from the previous version â€” correct any that still apply, non-negotiable)\n${JSON.stringify(verifier, null, 2)}`
  : '';

const userMessage = `# JOB DESCRIPTION
${descriptionHtml}

# CANDIDATE MASTER DOCUMENT
${masterDoc}

# CURRENT COVER LETTER (to be revised)
${coverLetterMarkdown}

# REVISION INSTRUCTIONS (from the candidate â€” the primary driver of this revision)
${instructions}${verifierBlock}

${OUTPUT_CONTRACT}`;

console.log(`[Agent 11 Build Prompt] system_prompt: ${systemPrompt.length} chars, user_message: ${userMessage.length} chars, instructions: ${instructions.length} chars, prior verifier: ${hasVerifier ? verifier.issues.length + ' issues' : 'none'}`);

return {
  json: {
    system_prompt: systemPrompt,
    user_message: userMessage,
    provider: input.provider,
    model: input.model,
    max_tokens: input.max_tokens || 8192
  }
};
